SELECT name, MAX(hp) AS max_hp
FROM monsters
GROUP BY name;

SELECT monster_id, SUM(impact) AS total_impact_weakness
FROM monster_parts
GROUP BY monster_id;

SELECT name, hp
FROM monsters
WHERE hp = (SELECT MAX(hp) FROM monsters);

SELECT reward_item, reward_quantity
FROM monster_rewards
WHERE monster_id = 0;

SELECT monster_id
FROM monster_elemental_weaknesses
WHERE elemental_type = 'water' AND weakness_value > 10;

SELECT reward_item, SUM(reward_quantity) AS total_quantity
FROM monster_rewards
GROUP BY reward_item;

SELECT part_id, monster_id, part_name, cut, impact, shot, fire
FROM monster_parts
WHERE monster_id = 0;

SELECT SUM(reward_quantity) AS total_rewards
FROM monster_rewards
WHERE monster_id = 0;

SELECT monster_id, MIN(weakness_value) AS min_weakness
FROM monster_elemental_weaknesses
GROUP BY monster_id;
